class Solution:
    def minCostClimbingStairs(self, cost):
        n = len(cost)
        from functools import lru_cache
        import sys
        sys.setrecursionlimit(5000)
        @lru_cache(None)
        def f(i):
            if i >= n:
                return 0
            return cost[i] + min(f(i + 1), f(i + 2))
        return min(f(0), f(1))

solutions.python:
class Solution:
    def minCostClimbingStairs(self, cost):
        a, b = 0, 0
        for c in cost:
            a, b = b, min(a, b) + c
        return min(a, b)

